// Une los textos del array "Mensaje" del nodo "Get Data"
// y devuelve un solo campo: "Mensaje Completo"

const mensajes = $node["Get Data"].json["Mensaje"];

if (Array.isArray(mensajes)) {
  return [
    {
      json: {
        "Mensaje Completo": mensajes.join(', ')
      }
    }
  ];
} else {
  return [
    {
      json: {
        "Mensaje Completo": null
      }
    }
  ];
}

