// n8n Code Node — Limpiar y estructurar servicios desde `concatenated_data`
//
// Entrada típica:
// [ { json: { concatenated_data: "[{...},{...},...]" } } ]
//
// Salida:
// [
//   { json: { numero, servicio, categoria, duracion, descripcion, profesional, precio } },
//   ...
// ]

const itemsIn = $input.all();

// 1) Obtener el JSON string
const first = itemsIn[0]?.json ?? {};
const raw = (first.concatenated_data ?? "").toString().trim();
if (!raw) return [];

// 2) Parse seguro
let rows = [];
try {
  rows = JSON.parse(raw);
  if (!Array.isArray(rows)) throw new Error("El contenido no es un array JSON.");
} catch (e) {
  throw new Error("`concatenated_data` no es un JSON válido: " + e.message);
}

// 3) Helpers
function toNumberEU(val) {
  if (val === null || val === undefined || val === "") return null;
  if (typeof val === "number") return Number(val);
  const s = String(val).trim().replace(/\s+/g, "").replace(",", ".");
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

function normalizarPrecioEUR(p) {
  let n = toNumberEU(p);
  if (n === null) return null;
  if (n > 100000) n = n / 100;
  else if (n > 1000 && n % 10 === 0) n = n / 100;
  return Number(n.toFixed(2));
}

function pick(r, keys) {
  for (const k of keys) {
    if (r[k] !== undefined && r[k] !== null && String(r[k]).trim() !== "") return r[k];
  }
  return undefined;
}

// 4) Transformar y devolver
const salida = rows.map((r) => {
  const numero = pick(r, ["Nº", "No", "Numero", "Número", "num", "n"]);
  const servicio = pick(r, ["Servicio", "Tratamiento", "servicio"]);
  const categoria = pick(r, ["Categoría", "Categoria", "Especialidad", "categoria"]);
  const duracion = pick(r, ["Duración", "Duracion", "duracion", "duración", "Tiempo"]);
  const descripcion = pick(r, ["Descripción", "Descripcion", "descripción", "descripcion", "Detalle"]);
  const profesional = pick(r, ["Profesional", "Especialista", "profesional"]);
  const precio = pick(r, ["Precio (€)", "Precio", "precio", "precio_eur"]);

  return {
    json: {
      numero: toNumberEU(numero),
      servicio: String(servicio ?? "").trim(),
      categoria: String(categoria ?? "").trim(),
      duracion: String(duracion ?? "").trim(),
      descripcion: String(descripcion ?? "").trim(),
      profesional: String(profesional ?? "").trim(),
      precio: normalizarPrecioEUR(precio),
    },
  };
});

return salida;

